+
+fn make_resolved_blocker(id: &str) -> BlockerEntry {
+    BlockerEntry {
+        id: id.to_string(),
+        title: format!("Resolved {id}"),
+        surface: BlockerSurface::Runtime,
+        severity: BlockerSeverity::Blocking,
+        remediation: RemediationStatus::Verified,
